# ci-adm - Eclipse Common Build Infrastructure Administration CLI
# Main entry point for CBI admin tools

set -o errexit
set -o nounset
set -o pipefail

# Get the directory where this script is located (follow symlinks)
SOURCE="${BASH_SOURCE[0]}"
while [ -h "$SOURCE" ]; do # resolve $SOURCE until the file is no longer a symlink
  SCRIPT_DIR="$(cd -P "$(dirname "$SOURCE")" && pwd)"
  SOURCE="$(readlink "$SOURCE")"
  [[ $SOURCE != /* ]] && SOURCE="$SCRIPT_DIR/$SOURCE" # if $SOURCE was a relative symlink, resolve it relative to the path where the symlink file was located
done
SCRIPT_DIR="$(cd -P "$(dirname "$SOURCE")" && pwd)"

# Color output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m' # No Color

# Print functions
print_error() {
  printf "${RED}Error: %s${NC}\n" "$*" >&2
}

print_success() {
  printf "${GREEN}✓ %s${NC}\n" "$*"
}

print_info() {
  printf "${BLUE} %s${NC}\n" "$*"
}

print_warning() {
  printf "${YELLOW}⚠ %s${NC}\n" "$*"
}

# Show usage
show_usage() {
  cat << EOF
$(printf "${BLUE}ci-adm${NC}") - Eclipse Common Build Infrastructure Administration CLI

$(printf "${GREEN}Usage:${NC}")
  ci-adm <module> <command> [arguments...]
  ci-adm help [module]
  ci-adm list

$(printf "${GREEN}Available Modules:${NC}")

  $(printf "${YELLOW}github${NC}")            GitHub integration management
  $(printf "${YELLOW}gitlab${NC}")            GitLab integration management
  $(printf "${YELLOW}gpg${NC}")               GPG key and signing management
  $(printf "${YELLOW}nexus${NC}")             Nexus repository management
  $(printf "${YELLOW}pass${NC}")              Password store management
  $(printf "${YELLOW}matrix${NC}")            Matrix bot management
  $(printf "${YELLOW}sonarcloud${NC}")        SonarCloud project management
  $(printf "${YELLOW}develocity${NC}")        Develocity bot setup
  $(printf "${YELLOW}project${NC}")           Project configuration management
  $(printf "${YELLOW}gitlab-runner${NC}")     GitLab runner provisioning
  $(printf "${YELLOW}service-accounts${NC}")  Service account management
  $(printf "${YELLOW}central-sonatype${NC}")  Maven Central / Sonatype setup
  $(printf "${YELLOW}projects-storage${NC}")  Projects storage setup
  $(printf "${YELLOW}buildtools${NC}")        Build tools management

$(printf "${GREEN}Examples:${NC}")
  ci-adm github setup-bot technology.cbi
  ci-adm gpg setup-signing technology.cbi
  ci-adm gitlab create-webhook technology.cbi
  ci-adm nexus create-repos technology.cbi
  ci-adm pass add-creds technology.cbi
  ci-adm help github
  ci-adm list

$(printf "${GREEN}Get Help:${NC}")
  ci-adm help          Show this help message
  ci-adm help <module> Show help for a specific module
  ci-adm list          List all available commands

EOF
}

