# Execute command
execute_command() {
  local module="$1"
  shift
  local command="${1:-}"
  
  if [[ -z "$command" ]]; then
    print_error "No command specified for module '$module'"
    echo ""
    show_module_help "$module"
    exit 1
  fi
  
  shift
  
  case "$module" in
    github)
      case "$command" in
        setup-bot)
          exec "${SCRIPT_DIR}/github/setup_github_bot.sh" "$@"
          ;;
        setup-otterdog)
          exec "${SCRIPT_DIR}/github/setup_otterdog.sh" "$@"
          ;;
        create-webhook)
          exec "${SCRIPT_DIR}/github/create_webhook.sh" "$@"
          ;;
        deploy-key)
          exec "${SCRIPT_DIR}/github/deploy-key.sh" "$@"
          ;;
        gen-credentials)
          exec "${SCRIPT_DIR}/github/gen-credentials.sh" "$@"
          ;;
        *)
          print_error "Unknown command for github: $command"
          echo ""
          show_module_help "github"
          exit 1
          ;;
      esac
      ;;
    
    gitlab)
      case "$command" in
        create-bot)
          exec "${SCRIPT_DIR}/gitlab/create_gitlab_bot_user.sh" "$@"
          ;;
        create-webhook)
          exec "${SCRIPT_DIR}/gitlab/create_gitlab_webhook.sh" "$@"
          ;;
        setup-jenkins)
          exec "${SCRIPT_DIR}/gitlab/setup_jenkins_gitlab_integration.sh" "$@"
          ;;
        setup-runner)
          exec "${SCRIPT_DIR}/gitlab/setup_gitlab_runner_integration.sh" "$@"
          ;;
        setup-license-vetting)
          exec "${SCRIPT_DIR}/gitlab/setup_license_vetting_workflow.sh" "$@"
          ;;
        admin)
          exec "${SCRIPT_DIR}/gitlab/gitlab_admin.sh" "$@"
          ;;
        *)
          print_error "Unknown command for gitlab: $command"
          echo ""
          show_module_help "gitlab"
          exit 1
          ;;
      esac
      ;;
    
    gpg)
      case "$command" in
        setup-signing)
          exec "${SCRIPT_DIR}/gpg/setup_gpg_signing.sh" "$@"
          ;;
        key-admin)
          exec "${SCRIPT_DIR}/gpg/gpg_key_admin.sh" "$@"
          ;;
        change-passphrase)
          exec "${SCRIPT_DIR}/gpg/change_gpg_passphrase.sh" "$@"
          ;;
        *)
          print_error "Unknown command for gpg: $command"
          echo ""
          show_module_help "gpg"
          exit 1
          ;;
      esac
      ;;
    
    nexus)
      case "$command" in
        create-repos)
          exec "${SCRIPT_DIR}/nexus/createNexusRepos.sh" "$@"
          ;;
        *)
          print_error "Unknown command for nexus: $command"
          echo ""
          show_module_help "nexus"
          exit 1
          ;;
      esac
      ;;
    
    pass)
      case "$command" in
        add-creds)
          exec "${SCRIPT_DIR}/pass/add_creds.sh" "$@"
          ;;
        add-creds-gpg)
          exec "${SCRIPT_DIR}/pass/add_creds_gpg.sh" "$@"
          ;;
        gen-ssh-key)
          exec "${SCRIPT_DIR}/pass/gen-ssh-key.sh" "$@"
          ;;
        change-ssh-passphrase)
          exec "${SCRIPT_DIR}/pass/change_SSH_passphrase.sh" "$@"
          ;;
        stats)
          exec "${SCRIPT_DIR}/pass/cbi_pass_bot_stats.sh" "$@"
          ;;
        *)
          print_error "Unknown command for pass: $command"
          echo ""
          show_module_help "pass"
          exit 1
          ;;
      esac
      ;;
    
    matrix)
      case "$command" in
        setup-bot)
          exec "${SCRIPT_DIR}/matrix/setup_matrix_bot.sh" "$@"
          ;;
        admin)
          exec "${SCRIPT_DIR}/matrix/matrix_admin.sh" "$@"
          ;;
        *)
          print_error "Unknown command for matrix: $command"
