          exec "${SCRIPT_DIR}/sonarcloud/create_sonarcloud_project.sh" "$@"
          ;;
        create-token)
          exec "${SCRIPT_DIR}/sonarcloud/create_sonarcloud_projects-token.sh" "$@"
          ;;
        *)
          print_error "Unknown command for sonarcloud: $command"
          echo ""
