          ;;
      esac
      ;;
    
    develocity)
      case "$command" in
        setup-bot)
          exec "${SCRIPT_DIR}/develocity/setup_develocity_bot.sh" "$@"
          ;;
        *)
          print_error "Unknown command for develocity: $command"
