          ;;
      esac
      ;;
    
    service-accounts)
      case "$command" in
        setup-pypi)
          exec "${SCRIPT_DIR}/service-accounts/setup_pypi_account.sh" "$@"
          ;;
        *)
          print_error "Unknown command for service-accounts: $command"
