    *)
      print_error "Unknown module: $module"
      echo ""
      show_usage
      exit 1
      ;;
  esac
}

# Main
main() {
  if [[ $# -eq 0 ]]; then
    show_usage
    exit 0
  fi
  
  case "$1" in
    help|-h|--help)
      if [[ $# -gt 1 ]]; then
        show_module_help "$2"
      else
        show_usage
      fi
      exit 0
      ;;
    
    list|-l|--list)
      show_all_commands
      exit 0
      ;;
    
    *)
      execute_command "$@"
      ;;
  esac
}

main "$@"
